<template>
    <view-page :defaultTable="false">
        <div class="view_page">
            <div class="row custom_row">
                <div class="col-xl-4 col-lg-12">
                    <fieldset>
                        <span class="legend">Media</span>
                        <div class="view_file">
                            <div class="row g-4">
                                <div class="col-lg-12">
                                    <div class="view_file_item text-center" style="width: 100%; height: 100%;">
                                        <div class="img" style="width: 100%; height: 100%;">
                                            <!-- <img :src="data?.image_one ?? emptyImage()" alt="img-cover"
                                                style="width: 100%; height: 100%; object-fit: cover;"> -->
                                            <img :src="data?.image_one == 'no_server_image' ? emptyServerImage() : (data?.image_one || emptyImage())"
                                                alt="img-cover" style="width: 100%; height: 100%; object-fit: cover" />
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </fieldset>
                </div>
                <div class="col-xl-8 col-lg-12">
                    <fieldset>
                        <span class="legend">Event Details</span>
                        <div class="table-responsive">
                            <table class="table table-striped">
                                <tbody>
                                    <tr>
                                        <th>Title</th>
                                        <th style="text-align: center;">:</th>
                                        <td>{{ data?.title ?? " " }}</td>
                                    </tr>
                                    <tr>
                                        <th>Category</th>
                                        <th style="text-align: center;">:</th>
                                        <td>{{ data?.category?.title ?? "" }}</td>
                                    </tr>
                                    <tr>
                                        <th>Venue</th>
                                        <th style="text-align: center;">:</th>
                                        <td>{{ data?.venue ?? "" }}</td>
                                    </tr>

                                    <tr>
                                        <th>Start Date</th>
                                        <th style="text-align: center;">:</th>
                                        <td>{{ data?.start_date ?? " " }}</td>
                                    </tr>
                                    <tr>
                                        <th>End Date</th>
                                        <th style="text-align: center;">:</th>
                                        <td>{{ data?.end_date ?? "" }}</td>
                                    </tr>
                                    <tr>
                                        <th>Highlighted Text</th>
                                        <th style="text-align: center;">:</th>
                                        <td>{{ data?.highlighted_text ?? "" }}</td>
                                    </tr>
                                    <tr>
                                        <th>Sorting</th>
                                        <th style="text-align: center;">:</th>
                                        <td>{{ data?.sorting ?? "" }}</td>
                                    </tr>
                                    <tr>
                                        <th>Status</th>
                                        <th style="text-align: center;">:</th>
                                        <td>
                                            <span :class="[
                                                data?.status == 'active'
                                                    ? 'bg-success'
                                                    : 'bg-danger ',
                                                'badge mt-1',
                                                'text-white ',]">{{ ucfirst(data?.status) }}
                                            </span>
                                        </td>
                                    </tr>
                                </tbody>
                            </table>
                        </div>
                    </fieldset>
                </div>
                <div class="col-xl-12 col-lg-12">
                    <fieldset>
                        <span class="legend">Event Schedule</span>
                        <div class="base_table_list mt-3" style="min-height: auto;">
                            <div class="table-responsive text-nowrap">
                                <table class="table">
                                    <thead>
                                        <tr>
                                            <th class="sl" style="min-width: 70px;">
                                                <span class="heading">
                                                    SL
                                                </span>
                                            </th>
                                            <th>
                                                <div class="heading">
                                                    Title
                                                </div>
                                            </th>
                                            <th>
                                                <div class="heading">
                                                    Date
                                                </div>
                                            </th>
                                            <th>
                                                <div class="heading">
                                                    Time
                                                </div>
                                            </th>
                                            <th>
                                                <div class="heading">
                                                    Description
                                                </div>
                                            </th>
                                            <th>
                                                <div class="heading">
                                                    Status
                                                </div>
                                            </th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        <tr v-if="!data.event_schedules || data.event_schedules.length === 0">
                                            <td colspan="6" class="text-center">No data found</td>
                                        </tr>

                                        <tr v-for="(item, index) in data.event_schedules" :key="index">
                                            <td>{{ index + 1 }}</td>
                                            <td>{{ item?.title || 'N/A' }}</td>
                                            <td>{{ item?.schedule_date ? formatDate(item?.schedule_date) : 'N/A' }}</td>
                                            <td>{{ this.formatTime(item?.schedule_time || 'N/A') }}</td>
                                            <td>{{ item?.description || 'N/A' }}</td>
                                            <td>
                                                <span :class="[
                                                    item?.status === 'active' ? 'bg-success' : 'bg-danger',
                                                    'badge mt-1',
                                                    'text-white'
                                                ]">
                                                    {{ ucfirst(item?.status || 'N/A') }}
                                                </span>
                                            </td>
                                        </tr>
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    </fieldset>
                </div>
                <div class="col-xl-12 col-lg-12">
                    <fieldset>
                        <span class="legend">Meta Information</span>
                        <template v-if="(data.meta_tag && data.meta_tag.length) || data.meta_description">
                            <div class="col-lg-12 mt-2" v-if="data.meta_tag && data.meta_tag.length">
                                <button class="btn btn-light border" v-for="(item, index) in data.meta_tag"
                                    :key="index">
                                    {{ item }}
                                </button>
                            </div>
                            <div class="col-lg-12 mt-2" v-if="data.meta_description">
                                <p>
                                    {{ data.meta_description }}
                                </p>
                            </div>
                        </template>
                        <template v-else>
                            <div class="col-lg-12 mt-2 text-center">
                                <p>No meta info found</p>
                            </div>
                        </template>
                    </fieldset>
                </div>
            </div>
        </div>


    </view-page>
</template>

<script>
const model = "events";

export default {
    data() {
        return {
            page_title: "Event View",
            model: model,
            data: {},
            fileColumns: [{ field: "thumb", title: "Image" }],
        };
    },
    methods: {
        formatDate(dateString) {
            const options = { day: 'numeric', month: 'short', year: 'numeric' };
            return new Date(dateString).toLocaleDateString('en-GB', options);
        },


    },
    created() {
        this.setBreadcrumbs(this.model, "view");
        this.get_data(`${this.model}/${this.$route.params.id}`);
    },
};
</script>
